#!/usr/bin/env python3
"""
Dependency Lock Management Script + Documentation (single-file)

Purpose
-------
Provide consistent, reproducible Python dependency versions across development and production by
standardizing how we generate and update lock files.

This script supports two common workflows:

1) pip-tools (requirements.txt with hashes)
   - Source of truth: requirements.in (and optionally requirements-dev.in)
   - Lock output: requirements.txt (and optionally requirements-dev.txt)
   - Uses hashes for supply-chain integrity and reproducibility.

2) Poetry (poetry.lock)
   - Source of truth: pyproject.toml
   - Lock output: poetry.lock
   - Uses Poetry's resolver and lock format.

Choose ONE workflow for a given project. Do not mix pip-tools and Poetry lock files unless you
have a deliberate, documented reason.

Repository Layout (recommended)
-------------------------------
pip-tools workflow:
  requirements.in
  requirements-dev.in            (optional)
  requirements.txt               (generated, committed)
  requirements-dev.txt           (generated, committed)

Poetry workflow:
  pyproject.toml                 (source of truth, committed)
  poetry.lock                    (generated, committed)

General Best Practices
----------------------
- Commit lock files to version control.
- Pin top-level dependencies in the source file (requirements.in or pyproject.toml).
- Use lock files in CI and production deployments.
- Update dependencies intentionally (scheduled cadence or security-driven).
- Prefer deterministic installs:
  - pip: use --require-hashes with a hashed requirements.txt
  - Poetry: use poetry install with a committed poetry.lock
- Keep Python version consistent across environments (e.g., via .python-version, tool-versions,
  CI config, Docker base image). Dependency resolution can vary by Python version/platform.

Usage
-----
This script provides commands to:
- generate/update lock files
- verify lock consistency
- install from lock files (optional convenience)

Examples:

pip-tools:
  python dep_lock.py piptools init
  python dep_lock.py piptools lock
  python dep_lock.py piptools lock --upgrade
  python dep_lock.py piptools verify
  python dep_lock.py piptools install

Poetry:
  python dep_lock.py poetry lock
  python dep_lock.py poetry lock --update
  python dep_lock.py poetry verify
  python dep_lock.py poetry install

CI Guidance
-----------
pip-tools:
  - Ensure requirements.txt is up to date:
      python dep_lock.py piptools verify
  - Install:
      python dep_lock.py piptools install

Poetry:
  - Ensure poetry.lock matches pyproject.toml:
      python dep_lock.py poetry verify
  - Install:
      python dep_lock.py poetry install

Notes on Updating Dependencies
------------------------------
pip-tools:
  - Regular lock (no upgrades): resolves using existing pins where possible.
  - Upgrade all: use --upgrade to refresh to newest allowed versions.
  - Upgrade specific packages: use --upgrade-package PKG (repeatable).

Poetry:
  - Regular lock: poetry lock (keeps versions unless constraints changed)
  - Update: poetry update (or poetry lock --no-update vs update behavior depends on Poetry version)
    This script uses:
      - poetry lock (default)
      - poetry update (when --update is passed)

Security / Integrity
--------------------
pip-tools hashed requirements:
  - requirements.txt includes hashes for each artifact.
  - Install with: pip install --require-hashes -r requirements.txt
  - This prevents dependency substitution and ensures exact artifacts.

Poetry:
  - poetry.lock pins versions and hashes internally.
  - Install with: poetry install --sync (recommended) to match lock exactly.

"""

from __future__ import annotations

import argparse
import os
import shutil
import subprocess
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import List, Optional


@dataclass
class RunResult:
    code: int


def run(cmd: List[str], cwd: Optional[Path] = None, env: Optional[dict] = None) -> RunResult:
    p = subprocess.run(cmd, cwd=str(cwd) if cwd else None, env=env, check=False)
    return RunResult(p.returncode)


def which_or_die(exe: str) -> str:
    p = shutil.which(exe)
    if not p:
        raise SystemExit(f"Missing required executable: {exe}")
    return p


def ensure_file(path: Path, content: str) -> None:
    if not path.exists():
        path.write_text(content, encoding="utf-8")


def project_root() -> Path:
    return Path.cwd()


# ----------------------------
# pip-tools workflow
# ----------------------------

PIPTOOLS_REQUIREMENTS_IN = "requirements.in"
PIPTOOLS_REQUIREMENTS_TXT = "requirements.txt"
PIPTOOLS_REQUIREMENTS_DEV_IN = "requirements-dev.in"
PIPTOOLS_REQUIREMENTS_DEV_TXT = "requirements-dev.txt"


def piptools_init(args: argparse.Namespace) -> int:
    root = project_root()
    ensure_file(
        root / PIPTOOLS_REQUIREMENTS_IN,
        "# Top-level production dependencies (pins/constraints allowed)\n"
        "# Example:\n"
        "# requests==2.32.3\n"
        "# fastapi>=0.110,<1\n"
        "\n",
    )
    ensure_file(
        root / PIPTOOLS_REQUIREMENTS_DEV_IN,
        "# Top-level development/test dependencies\n"
        "# Example:\n"
        "# -r requirements.in\n"
        "# pytest>=8,<9\n"
        "\n"
        "-r requirements.in\n",
    )
    return 0


def piptools_lock(args: argparse.Namespace) -> int:
    which_or_die("python")
    which_or_die("pip-compile")

    root = project_root()
    req_in = root / PIPTOOLS_REQUIREMENTS_IN
    dev_in = root / PIPTOOLS_REQUIREMENTS_DEV_IN

    if not req_in.exists():
        raise SystemExit(f"Missing {PIPTOOLS_REQUIREMENTS_IN}. Run: python dep_lock.py piptools init")

    base_cmd = [
        "pip-compile",
        "--generate-hashes",
        "--allow-unsafe",
        "--resolver=backtracking",
    ]

    if args.upgrade:
        base_cmd.append("--upgrade")

    for pkg in args.upgrade_package or []:
        base_cmd.extend(["--upgrade-package", pkg])

    out_txt = root / PIPTOOLS_REQUIREMENTS_TXT
    cmd = base_cmd + ["--output-file", str(out_txt), str(req_in)]
    r = run(cmd)
    if r.code != 0:
        return r.code

    if dev_in.exists():
        out_dev = root / PIPTOOLS_REQUIREMENTS_DEV_TXT
        cmd2 = base_cmd + ["--output-file", str(out_dev), str(dev_in)]
        r2 = run(cmd2)
        return r2.code

    return 0


def piptools_verify(args: argparse.Namespace) -> int:
    which_or_die("python")
    which_or_die("pip-compile")

    root = project_root()
    req_in = root / PIPTOOLS_REQUIREMENTS_IN
    req_txt = root / PIPTOOLS_REQUIREMENTS_TXT

    if not req_in.exists() or not req_txt.exists():
        raise SystemExit(f"Missing {PIPTOOLS_REQUIREMENTS_IN} or {PIPTOOLS_REQUIREMENTS_TXT}. Run lock first.")

    base_cmd = [
        "pip-compile",
        "--generate-hashes",
        "--allow-unsafe",
        "--resolver=backtracking",
        "--quiet",
    ]

    cmd = base_cmd + ["--output-file", str(req_txt), str(req_in), "--check"]
    r = run(cmd)
    if r.code != 0:
        return r.code

    dev_in = root / PIPTOOLS_REQUIREMENTS_DEV_IN
    dev_txt = root / PIPTOOLS_REQUIREMENTS_DEV_TXT
    if dev_in.exists() and dev_txt.exists():
        cmd2 = base_cmd + ["--output-file", str(dev_txt), str(dev_in), "--check"]
        r2 = run(cmd2)
        return r2.code

    return 0


def piptools_install(args: argparse.Namespace) -> int:
    which_or_die("python")
    which_or_die("pip")

    root = project_root()
    req_txt = root / PIPTOOLS_REQUIREMENTS_TXT
    if not req_txt.exists():
        raise SystemExit(f"Missing {PIPTOOLS_REQUIREMENTS_TXT}. Run: python dep_lock.py piptools lock")

    cmd = ["python", "-m", "pip", "install", "--require-hashes", "-r", str(req_txt)]
    r = run(cmd)
    if r.code != 0:
        return r.code

    if args.dev:
        dev_txt = root / PIPTOOLS_REQUIREMENTS_DEV_TXT
        if not dev_txt.exists():
            raise SystemExit(f"Missing {PIPTOOLS_REQUIREMENTS_DEV_TXT}. Run: python dep_lock.py piptools lock")
        cmd2 = ["python", "-m", "pip", "install", "--require-hashes", "-r", str(dev_txt)]
        r2 = run(cmd2)
        return r2.code

    return 0


# ----------------------------
# Poetry workflow
# ----------------------------

def poetry_lock(args: argparse.Namespace) -> int:
    which_or_die("poetry")
    root = project_root()
    pyproject = root / "pyproject.toml"
    if not pyproject.exists():
        raise SystemExit("Missing pyproject.toml (Poetry workflow requires it).")

    if args.update:
        r = run(["poetry", "update"])
        return r.code

    r = run(["poetry", "lock"])
    return r.code


def poetry_verify(args: argparse.Namespace) -> int:
    which_or_die("poetry")
    root = project_root()
    pyproject = root / "pyproject.toml"
    lockfile = root / "poetry.lock"
    if not pyproject.exists() or not lockfile.exists():
        raise SystemExit("Missing pyproject.toml or poetry.lock. Run: python dep_lock.py poetry lock")

    # Poetry provides "poetry lock --check" in newer versions; fall back to "poetry check".
    r = run(["poetry", "lock", "--check"])
    if r.code == 0:
        return 0

    r2 = run(["poetry", "check"])
    return r2.code


def poetry_install(args: argparse.Namespace) -> int:
    which_or_die("poetry")
    cmd = ["poetry", "install", "--sync"]
    if args.no_root:
        cmd.append("--no-root")
    if args.only:
        cmd.extend(["--only", args.only])
    if args.with_groups:
        cmd.extend(["--with", args.with_groups])
    if args.without_groups:
        cmd.extend(["--without", args.without_groups])
    r = run(cmd)
    return r.code


# ----------------------------
# CLI
# ----------------------------

def build_parser() -> argparse.ArgumentParser:
    p = argparse.ArgumentParser(prog="dep_lock.py", description="Manage Python dependency lock files (pip-tools or Poetry).")
    sub = p.add_subparsers(dest="tool", required=True)

    # pip-tools
    piptools = sub.add_parser("piptools", help="pip-tools workflow (requirements.in -> requirements.txt with hashes)")
    piptools_sub = piptools.add_subparsers(dest="cmd", required=True)

    piptools_sub.add_parser("init", help="Create starter requirements.in and requirements-dev.in if missing")

    lock = piptools_sub.add_parser("lock", help="Generate/update requirements.txt (and dev) with hashes")
    lock.add_argument("--upgrade", action="store_true", help="Upgrade all dependencies within constraints")
    lock.add_argument("--upgrade-package", action="append", default=[], help="Upgrade a specific package (repeatable)")

    piptools_sub.add_parser("verify", help="Verify lock files are up to date (pip-compile --check)")

    install = piptools_sub.add_parser("install", help="Install from hashed lock files")
    install.add_argument("--dev", action="store_true", help="Also install dev lock file")

    # Poetry
    poetry = sub.add_parser("poetry", help="Poetry workflow (pyproject.toml -> poetry.lock)")
    poetry_sub = poetry.add_subparsers(dest="cmd", required=True)

    plock = poetry_sub.add_parser("lock", help="Generate/update poetry.lock")
    plock.add_argument("--update", action="store_true", help="Update dependencies (poetry update)")

    poetry_sub.add_parser("verify", help="Verify poetry.lock matches pyproject.toml")

    pinstall = poetry_sub.add_parser("install", help="Install from poetry.lock (sync environment)")
    pinstall.add_argument("--no-root", action="store_true", help="Do not install the project package itself")
    pinstall.add_argument("--only", default=None, help="Install only dependency group(s), e.g. 'main'")
    pinstall.add_argument("--with", dest="with_groups", default=None, help="Install with group(s), e.g. 'dev,test'")
    pinstall.add_argument("--without", dest="without_groups", default=None, help="Install without group(s), e.g. 'dev'")

    return p


def main(argv: List[str]) -> int:
    parser = build_parser()
    args = parser.parse_args(argv)

    if args.tool == "piptools":
        if args.cmd == "init":
            return piptools_init(args)
        if args.cmd == "lock":
            return piptools_lock(args)
        if args.cmd == "verify":
            return piptools_verify(args)
        if args.cmd == "install":
            return piptools_install(args)

    if args.tool == "poetry":
        if args.cmd == "lock":
            return poetry_lock(args)
        if args.cmd == "verify":
            return poetry_verify(args)
        if args.cmd == "install":
            return poetry_install(args)

    parser.print_help()
    return 2


if __name__ == "__main__":
    raise SystemExit(main(sys.argv[1:]))